import{_ as t,o as s,c as i,ae as n}from"./chunks/framework.BMMOQqto.js";const k=JSON.parse('{"title":"Q4: JVM内存模型和垃圾回收算法？","description":"","frontmatter":{},"headers":[],"relativePath":"01-java/q4-jvm.md","filePath":"01-java/q4-jvm.md"}'),e={name:"01-java/q4-jvm.md"};function r(l,a,d,h,o,p){return s(),i("div",null,[...a[0]||(a[0]=[n(`<h1 id="q4-jvm内存模型和垃圾回收算法" tabindex="-1">Q4: JVM内存模型和垃圾回收算法？ <a class="header-anchor" href="#q4-jvm内存模型和垃圾回收算法" aria-label="Permalink to &quot;Q4: JVM内存模型和垃圾回收算法？&quot;">​</a></h1><h2 id="jvm内存模型-jmm" tabindex="-1">JVM内存模型（JMM） <a class="header-anchor" href="#jvm内存模型-jmm" aria-label="Permalink to &quot;JVM内存模型（JMM）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>区域</th><th>线程私有/共享</th><th>存储内容</th><th>异常</th></tr></thead><tbody><tr><td>堆（Heap）</td><td>共享</td><td>对象实例、数组</td><td>OutOfMemoryError</td></tr><tr><td>栈（Stack）</td><td>私有</td><td>局部变量、操作数栈</td><td>StackOverflowError</td></tr><tr><td>方法区</td><td>共享</td><td>类信息、常量、静态变量</td><td>OutOfMemoryError</td></tr><tr><td>本地方法栈</td><td>私有</td><td>Native方法服务</td><td>StackOverflowError</td></tr><tr><td>程序计数器</td><td>私有</td><td>字节码行号指示器</td><td>无</td></tr></tbody></table><h2 id="堆内存划分" tabindex="-1">堆内存划分 <a class="header-anchor" href="#堆内存划分" aria-label="Permalink to &quot;堆内存划分&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>堆内存 = 新生代 + 老年代 + 元空间(1.8+)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>新生代（1/3堆）：</span></span>
<span class="line"><span>  - Eden区（8/10）</span></span>
<span class="line"><span>  - Survivor区 From（1/10）</span></span>
<span class="line"><span>  - Survivor区 To（1/10）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>老年代（2/3堆）</span></span></code></pre></div><h2 id="垃圾回收算法" tabindex="-1">垃圾回收算法 <a class="header-anchor" href="#垃圾回收算法" aria-label="Permalink to &quot;垃圾回收算法&quot;">​</a></h2><h3 id="_1-标记-清除算法-mark-sweep" tabindex="-1">① 标记-清除算法（Mark-Sweep） <a class="header-anchor" href="#_1-标记-清除算法-mark-sweep" aria-label="Permalink to &quot;① 标记-清除算法（Mark-Sweep）&quot;">​</a></h3><ul><li><strong>步骤</strong>：标记存活对象 → 清除死亡对象</li><li><strong>缺点</strong>：产生内存碎片</li></ul><h3 id="_2-标记-整理算法-mark-compact" tabindex="-1">② 标记-整理算法（Mark-Compact） <a class="header-anchor" href="#_2-标记-整理算法-mark-compact" aria-label="Permalink to &quot;② 标记-整理算法（Mark-Compact）&quot;">​</a></h3><ul><li><strong>步骤</strong>：标记存活对象 → 移动到一端 → 清除边界外对象</li><li><strong>优点</strong>：无内存碎片</li><li><strong>适用</strong>：老年代</li></ul><h3 id="_3-复制算法-copying" tabindex="-1">③ 复制算法（Copying） <a class="header-anchor" href="#_3-复制算法-copying" aria-label="Permalink to &quot;③ 复制算法（Copying）&quot;">​</a></h3><ul><li><strong>步骤</strong>：分成两块相等空间FROM/TO，FROM满时将存活对象复制到TO</li><li><strong>优点</strong>：无内存碎片，分配简单</li><li><strong>缺点</strong>：空间浪费50%</li><li><strong>适用</strong>：新生代（对象存活率低）</li></ul><h3 id="_4-分代收集算法" tabindex="-1">④ 分代收集算法 <a class="header-anchor" href="#_4-分代收集算法" aria-label="Permalink to &quot;④ 分代收集算法&quot;">​</a></h3><ul><li><strong>新生代</strong>：Minor GC，使用复制算法</li><li><strong>老年代</strong>：Full/Major GC，使用标记-清除或标记-整理</li></ul><h2 id="垃圾回收器" tabindex="-1">垃圾回收器 <a class="header-anchor" href="#垃圾回收器" aria-label="Permalink to &quot;垃圾回收器&quot;">​</a></h2><table tabindex="0"><thead><tr><th>回收器</th><th>特点</th><th>适用场景</th></tr></thead><tbody><tr><td>Serial</td><td>单线程，Stop The World</td><td>client模式</td></tr><tr><td>Parallel</td><td>多线程，关注吞吐量</td><td>后台计算</td></tr><tr><td>CMS</td><td>并发标记清除，关注停顿时间</td><td>web服务</td></tr><tr><td>G1</td><td>区域化分代，平衡吞吐量和停顿</td><td>服务端</td></tr><tr><td>ZGC</td><td>超低延迟（&lt;10ms）</td><td>大内存低延迟</td></tr></tbody></table><h2 id="常见jvm参数" tabindex="-1">常见JVM参数 <a class="header-anchor" href="#常见jvm参数" aria-label="Permalink to &quot;常见JVM参数&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-Xms4g</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Xmx4g</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                    # 堆初始和最大</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-Xmn2g</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                              # 新生代大小</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-XX:NewRatio</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                      # 老年代/新生代=2</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-XX:+UseG1GC</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                        # 使用G1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-XX:MaxGCPauseMillis</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=200</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 最大GC停顿时间</span></span></code></pre></div>`,18)])])}const g=t(e,[["render",r]]);export{k as __pageData,g as default};
